# # # #             layer = model.model.layers[layer_idx]

# # # #         act_fn = layer.mlp.act_fn

# # # #         # Each accumulator tracks: count, mean, M2, min-heap, max-heap
# # # #         acc = {
# # # #             'count': 0,
# # # #             'mean': None,
# # # #             'M2': None,
# # # #             'all_vals': [],  # store a subsample for percentiles
